    // ============================================================
    // OBJETIVO
    // Evaluar SOLO las últimas 3 ejecuciones reales del job
    // mlp-prd-caj-pisystem-job04
    //
    // Reglas:
    // - ALERTAR si:
    //      * >= 2 errores
    //      * >= 3 warnings
    // - Caso contrario: No Alertar
    // ============================================================
    let endQuery = bin($__timeTo, 1m);
    // ------------------------------------------------
    // BASE DE DATOS (SYSTEM + LOGS)
    // ------------------------------------------------
    let base =
        union
        (
            // -----------------------------
            // SYSTEM LOGS → Ejecuciones OK
            // -----------------------------
            ContainerAppSystemLogs_CL
            | where TimeGenerated between (endQuery-20m .. endQuery)
            | where JobName_s == "mlp-prd-caj-pisystem-job04"
            | project
                ejecucion = bin(TimeGenerated, 5m),
                nombreReal = "mlp-prd-caj-pisystem-job04_ejecucion",
                status = "n"
        ),
        (
            // -----------------------------
            // CONSOLE LOGS → ERRORES
            // -----------------------------
            ContainerAppConsoleLogs_CL
            | where TimeGenerated between (endQuery-20m .. endQuery)
            | where ContainerJobName_s == "mlp-prd-caj-pisystem-job04"
            | where Log_s contains "ERROR"
            | project
                ejecucion = bin(TimeGenerated, 5m),
                nombreReal = "mlp-prd-caj-pisystem-job04_logs",
                status = "e"
        ),
        (
            // -----------------------------
            // CONSOLE LOGS → WARNINGS
            // -----------------------------
            ContainerAppConsoleLogs_CL
            | where TimeGenerated between (endQuery-20m .. endQuery)
            | where ContainerJobName_s == "mlp-prd-caj-pisystem-job04"
            | where Log_s contains "WARNING"
            | project
                ejecucion = bin(TimeGenerated, 5m),
                nombreReal = "mlp-prd-caj-pisystem-job04_logs",
                status = "w"
        );
    // ------------------------------------------------
    // NORMALIZAR: 1 STATUS POR EJECUCIÓN
    // Prioridad: ERROR > WARNING > OK
    // ------------------------------------------------
    let por_ejecucion =
        base
        | summarize
            status = case(
                countif(status == "e") > 0, "e",
                countif(status == "w") > 0, "w",
                "n"
            )
          by nombreReal, ejecucion;
    // ------------------------------------------------
    // TOMAR ÚLTIMAS 3 EJECUCIONES POR CADA STREAM
    // (system y logs por separado)
    // ------------------------------------------------
    let ultimas_3 =
        por_ejecucion
        | partition hint.strategy=native by nombreReal
        (
            sort by ejecucion desc
            | take 3
        );
    // ------------------------------------------------
    // APLICAR REGLAS DE NEGOCIO
    // ------------------------------------------------
    let evaluacion =
        ultimas_3
        | summarize
            fallas   = countif(status == "e"),
            warnings = countif(status == "w"),
            total    = count()
          by nombreReal
        | extend estado =
            iff(fallas >= 2, "Alertar",
            iff(warnings >= 3, "Alertar",
            "No Alertar"));
//};
evaluacion
| extend color = iff(estado == "Alertar", "#E53935", "#EAF4EA")
| project color, estado
// IMPORTANTÍSIMO: quita comillas/espacios/saltos
| extend color = trim(' "\t\r\n', tostring(color))
// Entrega un único valor
| project color
| take 1

