// =====================================================
// FUNCIÓN REUTILIZABLE PARA DIFUSIÓN
// =====================================================
// =====================================================
let evaluar_difusion = (jobIds:dynamic)
{
    let JOBS =
        DatabricksJobs
        | where TimeGenerated >= startQuery - 2d and TimeGenerated < endQuery
        | extend j = parse_json(RequestParams)
        | extend jobID = tostring(j.jobId),
                 state = tostring(j.jobTerminalState)
        | where jobID in (jobIds);
    JOBS
    | summarize arg_max(TimeGenerated, state) by jobID
    | extend Estado =
        case(
            state in ("Failed","Cancelled"), "Alertar",
            state == "Succeeded", "No Alertar",
            state == "Running", "No Alertar",
            "Warning"
        )
    | summarize hayAlertas = countif(Estado == "Alertar")
    | extend Estado = iff(hayAlertas > 0, "Alertar", "No Alertar")
    | project Estado
};
